/*
  Global design system based on the chalet e-store layout
  - Clean, modern, resort-branded corporate style
  - Strong primary blue banner, white content, subtle grays
*/

:root {
  /* Brand palette */
  --color-primary-500: #0095FF; /* top bar / active link */
  --color-primary-600: #007AD6; /* darker blue for hover */

  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F5F5F5;
  --color-neutral-200: #CCCCCC;
  --color-neutral-250: #E0E0E0;
  --color-neutral-700: #555555;
  --color-neutral-800: #333333;
  --color-neutral-900: #222222;

  --color-success: #28A745;
  --color-error: #DC3545;
  --color-warning: #FFC107;
  --color-info: #17A2B8;

  /* Typography */
  --font-heading: 'Poppins', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  /* Layout */
  --header-top-bar-height: 40px;
  --header-nav-height: 64px;
  --container-max-width: 1120px;
  --border-radius-sm: 4px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-000);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-primary-500);
  text-decoration: none;
}

a:hover,
a:focus {
  color: var(--color-primary-600);
  text-decoration: none;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  color: var(--color-neutral-900);
  margin-top: 0;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-bold);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-semibold);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-semibold);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-sm);
}

small {
  font-size: var(--font-size-small);
}

/* Layout helpers */

.container {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding-left: var(--space-md);
  padding-right: var(--space-md);
}

.page-content {
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xl);
}

/* Header styling */

.site-header {
  font-family: var(--font-heading);
}

/* Top contact bar */

.top-bar {
  background-color: var(--color-primary-500);
  color: var(--color-neutral-000);
  height: var(--header-top-bar-height);
  display: flex;
  align-items: center;
}

.top-bar-inner {
  display: flex;
  align-items: center;
  justify-content: flex-start;
}

.top-bar-contact {
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-medium);
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.contact-item {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.contact-icon {
  font-size: 13px;
}

.contact-text {
  white-space: nowrap;
}

.contact-separator {
  opacity: 0.7;
}

/* Main navigation bar */

.main-nav {
  background-color: var(--color-neutral-000);
  border-bottom: 1px solid var(--color-neutral-250);
}

.nav-inner {
  height: var(--header-nav-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

/* Brand / logo */

.brand {
  display: inline-flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: center;
  padding-top: 4px;
  padding-bottom: 4px;
  color: var(--color-neutral-900);
}

.brand-mark {
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.brand-subtitle {
  font-size: 11px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

/* Primary nav links */

.primary-nav {
  flex: 1 1 auto;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  align-items: stretch;
  gap: 4px;
}

.nav-item {
  position: relative;
}

.nav-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 var(--space-md);
  height: var(--header-nav-height);
  font-size: 15px;
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-700);
  text-decoration: none;
  white-space: nowrap;
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-primary-500);
}

.nav-link.is-current,
.nav-item.is-current > .nav-link {
  color: var(--color-primary-500);
}

/* Secondary duplicate links (for Store categories) are slightly deemphasized */

.nav-item-secondary .nav-link {
  font-size: 14px;
  padding-inline: 14px;
}

/* Store dropdown */

.has-dropdown .nav-link-parent {
  gap: 6px;
}

.nav-caret {
  font-size: 11px;
  margin-left: 2px;
}

.has-dropdown {
  position: relative;
}

.nav-dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  min-width: 220px;
  background-color: var(--color-neutral-000);
  border: 1px solid var(--color-neutral-250);
  border-radius: var(--border-radius-sm);
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.06);
  padding: var(--space-xs) 0;
  display: none;
  z-index: 20;
}

.has-dropdown:hover .nav-dropdown,
.has-dropdown:focus-within .nav-dropdown {
  display: block;
}

.dropdown-link {
  display: block;
  padding: 8px 18px;
  font-size: 14px;
  color: var(--color-neutral-700);
}

.dropdown-link:hover,
.dropdown-link:focus {
  background-color: var(--color-neutral-050);
  color: var(--color-primary-600);
}

/* Right utility area (cart indicator) */

.nav-extra {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  min-width: 120px;
}

.cart-indicator {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 14px;
  color: var(--color-neutral-700);
}

.cart-icon {
  font-size: 15px;
}

.cart-text {
  white-space: nowrap;
}

/* Footer styling */

.site-footer {
  border-top: 1px solid var(--color-neutral-250);
  background-color: var(--color-neutral-050);
  margin-top: var(--space-xl);
}

.footer-main {
  padding-top: var(--space-lg);
  padding-bottom: var(--space-lg);
}

.footer-inner {
  display: flex;
  justify-content: center;
}

.footer-nav {
  width: 100%;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-sm) var(--space-lg);
}

.footer-item {
  flex: 0 0 auto;
}

.footer-link {
  font-size: 14px;
  color: var(--color-neutral-700);
  font-weight: var(--font-weight-regular);
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-primary-500);
}

.footer-bottom {
  border-top: 1px solid var(--color-neutral-250);
  background-color: var(--color-neutral-000);
}

.footer-bottom-inner {
  padding-top: var(--space-sm);
  padding-bottom: var(--space-sm);
  display: flex;
  justify-content: center;
  align-items: center;
}

.footer-copy {
  margin: 0;
  font-size: 13px;
  color: var(--color-neutral-700);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .nav-inner {
    flex-wrap: wrap;
    height: auto;
    padding-top: var(--space-xs);
    padding-bottom: var(--space-xs);
  }

  .primary-nav {
    order: 3;
    width: 100%;
    margin-top: var(--space-xs);
  }

  .nav-list {
    flex-wrap: wrap;
    justify-content: center;
  }

  .nav-link {
    height: 44px;
    padding-inline: 12px;
  }

  .nav-extra {
    order: 2;
  }

  .brand {
    order: 1;
  }
}

@media (max-width: 640px) {
  .top-bar-inner {
    justify-content: center;
  }

  .top-bar-contact {
    flex-wrap: wrap;
    text-align: center;
  }

  .footer-links {
    flex-direction: column;
    align-items: center;
  }
}
